document.addEventListener("DOMContentLoaded",(()=>{if("undefined"==typeof gsap)return;gsap.registerPlugin(ScrollTrigger);const e=document.querySelector(".topppa-blog-post-wrapper .row");if(!e)return;const o=e.querySelectorAll('[class*="col-"]');o.length&&ScrollTrigger.batch(o,{start:"top 80%",toggleActions:"play none play none",once:!0,onEnter:e=>gsap.fromTo(e,{opacity:0,y:40},{opacity:1,y:0,duration:.9,ease:"power3.out",stagger:.12,clearProps:"all"}),once:!0})}));